(window.webpackJsonp=window.webpackJsonp||[]).push([[732],{730:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Definition for a binary tree node.\\n * function TreeNode(val) {\\n *     this.val = val;\\n *     this.left = this.right = null;\\n * }\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{TreeNode}</span> <span class=\\"hljs-variable\\">root</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> maxProduct = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">root</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> sum=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">let</span> MOD=<span class=\\"hljs-number\\">1e9</span>+<span class=\\"hljs-number\\">7</span>\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">dfs</span>(<span class=\\"hljs-params\\">root</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(!root)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">0</span>\\n    root.leftSum=dfs(root.left)\\n    root.rightSum=dfs(root.right)\\n    sum+=root.val\\n    <span class=\\"hljs-keyword\\">return</span> root.leftSum+root.rightSum+root.val\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> max=<span class=\\"hljs-number\\">-1</span>\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">dfs2</span>(<span class=\\"hljs-params\\">root</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(root.left){\\n      max=<span class=\\"hljs-built_in\\">Math</span>.max(max,root.leftSum*(sum-root.leftSum))\\n      dfs2(root.left)\\n    }\\n    <span class=\\"hljs-keyword\\">if</span>(root.right){\\n      max=<span class=\\"hljs-built_in\\">Math</span>.max(max,root.rightSum*(sum-root.rightSum))\\n      dfs2(root.right)\\n    }\\n  }\\n  dfs(root)\\n  dfs2(root)\\n  <span class=\\"hljs-keyword\\">return</span> max % MOD\\n};\\n</code></pre>\\n"],"titleSlug":"maximum-product-of-splitted-binary-tree","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u68f5\u4e8c\u53c9\u6811\uff0c\u5b83\u7684\u6839\u4e3a&nbsp;<code>root</code> \u3002\u8bf7\u4f60\u5220\u9664 1 \u6761\u8fb9\uff0c\u4f7f\u4e8c\u53c9\u6811\u5206\u88c2\u6210\u4e24\u68f5\u5b50\u6811\uff0c\u4e14\u5b83\u4eec\u5b50\u6811\u548c\u7684\u4e58\u79ef\u5c3d\u53ef\u80fd\u5927\u3002</p>\\n\\n<p>\u7531\u4e8e\u7b54\u6848\u53ef\u80fd\u4f1a\u5f88\u5927\uff0c\u8bf7\u4f60\u5c06\u7ed3\u679c\u5bf9 10^9 + 7 \u53d6\u6a21\u540e\u518d\u8fd4\u56de\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><strong><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/02/02/sample_1_1699.png\\" style=\\"height: 200px; width: 495px;\\"></strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>root = [1,2,3,4,5,6]\\n<strong>\u8f93\u51fa\uff1a</strong>110\\n<strong>\u89e3\u91ca\uff1a</strong>\u5220\u9664\u7ea2\u8272\u7684\u8fb9\uff0c\u5f97\u5230 2 \u68f5\u5b50\u6811\uff0c\u548c\u5206\u522b\u4e3a 11 \u548c 10 \u3002\u5b83\u4eec\u7684\u4e58\u79ef\u662f 110 \uff0811*10\uff09\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/02/02/sample_2_1699.png\\" style=\\"height: 200px; width: 495px;\\"></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>root = [1,null,2,3,4,null,null,5,6]\\n<strong>\u8f93\u51fa\uff1a</strong>90\\n<strong>\u89e3\u91ca\uff1a</strong>\u79fb\u9664\u7ea2\u8272\u7684\u8fb9\uff0c\u5f97\u5230 2 \u68f5\u5b50\u6811\uff0c\u548c\u5206\u522b\u662f 15 \u548c 6 \u3002\u5b83\u4eec\u7684\u4e58\u79ef\u4e3a 90 \uff0815*6\uff09\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>root = [2,3,9,10,7,8,6,5,4,11,1]\\n<strong>\u8f93\u51fa\uff1a</strong>1025\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>root = [1,1]\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li>\u6bcf\u68f5\u6811\u6700\u591a\u6709&nbsp;<code>50000</code>&nbsp;\u4e2a\u8282\u70b9\uff0c\u4e14\u81f3\u5c11\u6709&nbsp;<code>2</code>&nbsp;\u4e2a\u8282\u70b9\u3002</li>\\n\\t<li>\u6bcf\u4e2a\u8282\u70b9\u7684\u503c\u5728&nbsp;<code>[1, 10000]</code>&nbsp;\u4e4b\u95f4\u3002</li>\\n</ul>\\n","title":"1339. \u5206\u88c2\u4e8c\u53c9\u6811\u7684\u6700\u5927\u4e58\u79ef","relatedTags":["\u6811","\u52a8\u6001\u89c4\u5212"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1339"}')}}]);